import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function App() {
  const [data, setData] = React.useState(appsmith.model || {});
  const [cost, setCost] = React.useState('');
  const costRef = React.useRef('');

  React.useEffect(() => {
    const unsub = appsmith.onModelChange((m) => {
      setData(m || {});
      if (!costRef.current) {
        const initCost = m?.selectedRow?.part_cost || '';
        setCost(initCost);
        costRef.current = initCost;
      }
    });
    return () => typeof unsub === 'function' && unsub();
  }, []);

  const part = data.selectedRow || {};
  const dest = data.destAsset || {};

  if (!part.part_type) return null;

  const isInStock = part.availability === 'in_stock';

  const availStyle = isInStock
    ? { background: '#dcfce7', color: '#15803d' }
    : { background: '#fef3c7', color: '#92400e' };

  const availText = isInStock
    ? '✓ In Stock — ready to install'
    : '⚠ Still in donor asset — removal will be triggered';

  const handleCostChange = (e) => {
    setCost(e.target.value);
    costRef.current = e.target.value;
  };

  const handleCostBlur = (e) => {
    const val = e.target.value;
    costRef.current = val;
    appsmith.updateModel({ cost: val ? parseFloat(val) : null });
    appsmith.triggerEvent('costChanged');
  };

  return (
    <div style={{
      fontFamily: 'sans-serif',
      padding: '16px',
      background: '#f8fafc',
      borderRadius: '10px',
      border: '1px solid #e2e8f0'
    }}>
      <div style={{ marginBottom: '12px', display: 'flex', alignItems: 'center', gap: '8px' }}>
        <span style={{ fontSize: '13px', fontWeight: 700, color: '#475569', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Selected Part</span>
        <span style={{
          ...availStyle,
          fontSize: '11px',
          fontWeight: 600,
          padding: '2px 10px',
          borderRadius: '999px'
        }}>{availText}</span>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '10px', marginBottom: '14px' }}>
        <div style={tile}>
          <div style={tileLabel}>Part Type</div>
          <div style={tileValue}>{part.part_type || '—'}</div>
        </div>
        <div style={tile}>
          <div style={tileLabel}>Donor Asset</div>
          <div style={tileValue}>{(part.donor_make || '') + ' ' + (part.donor_model || '')}</div>
          <div style={tileSub}>{part.donor_asset_ref || '—'}</div>
        </div>
        <div style={tile}>
          <div style={tileLabel}>Serial / Grade</div>
          <div style={tileValue}>{part.serial_number || '—'}</div>
          <div style={tileSub}>Grade: {part.condition_grade || '—'}</div>
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px 14px', background: '#e0f2fe', borderRadius: '8px', marginBottom: '10px' }}>
        <span style={{ fontSize: '13px', color: '#0369a1' }}>➜</span>
        <div>
          <div style={{ fontSize: '11px', color: '#0369a1', fontWeight: 600, textTransform: 'uppercase' }}>Installing into</div>
          <div style={{ fontSize: '14px', fontWeight: 700, color: '#0c4a6e' }}>
            {(dest.make_name || '') + ' ' + (dest.model_name || '') + ' — ' + (dest.asset_ref || '—')}
          </div>
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        <label style={{ fontSize: '13px', fontWeight: 600, color: '#475569', whiteSpace: 'nowrap' }}>Cost (£)</label>
        <input
          type="number"
          value={cost}
          onChange={handleCostChange}
          onBlur={handleCostBlur}
          placeholder="0.00"
          style={{
            width: '120px',
            padding: '6px 10px',
            borderRadius: '6px',
            border: '1px solid #cbd5e1',
            fontSize: '14px',
            outline: 'none'
          }}
        />
      </div>
    </div>
  );
}

const tile = {
  background: '#fff',
  borderRadius: '8px',
  padding: '10px 12px',
  border: '1px solid #e2e8f0'
};
const tileLabel = {
  fontSize: '11px',
  color: '#94a3b8',
  fontWeight: 600,
  textTransform: 'uppercase',
  marginBottom: '4px'
};
const tileValue = {
  fontSize: '14px',
  fontWeight: 700,
  color: '#1e293b'
};
const tileSub = {
  fontSize: '12px',
  color: '#64748b',
  marginTop: '2px'
};

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
